    margin-top: 0.35rem;
    transition: background-color 0.2s ease;
}
.rc-reply:hover .rc-connector {
    background-color: var(--accent-amber);
}
.rc-connector--hidden {
    visibility: hidden;
}

.rc-content {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    flex: 1;
    min-width: 0;
}

.rc-user-row {
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.rc-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
}
.rc-username {
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-heading);
}
.rc-dot {
    color: var(--text-separator);
    font-size: 0.75rem;
