    overflow-wrap: anywhere;
    word-break: break-word;
    white-space: pre-wrap;
}

.rc-actions {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding-top: 0.15rem;
}
.rc-show-replies {
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
