}
.rc-show-replies:hover {
    opacity: 0.8;
}
.rc-reply-btn {
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--text-muted);
    transition: color 0.15s ease;
}
.rc-reply-btn:hover {
    color: var(--accent-amber);
}

.rc-inline-composer {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    overflow: hidden;
    padding-top: 0.25rem;
}

.rc-load-more {
    display: inline-flex;
    align-items: center;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.35rem 0;
    margin-top: 0.25rem;
    margin-left: calc(32px + 0.65rem);
