        margin-bottom: 0;
    }
    .so-avatar-outer {
        width: 30px;
        height: 30px;
    }
    .so-avatar-outer .so-avatar {
        width: 30px;
        height: 30px;
    }
    .so-avatar-outer.avatar-ring-legend,
    .so-avatar-outer.avatar-ring-og {
        display: flex;
        align-items: center;
        justify-content: center;
        width: auto;
        height: auto;
    }
    .so-avatar-outer.avatar-ring-legend .so-avatar,
    .so-avatar-outer.avatar-ring-og .so-avatar {
        width: 30px;
        height: 30px;
    }
    .so-card {
        padding: 0.75rem 0;
    }
    .so-avatar {
        width: 30px;
        height: 30px;
    }
    .so-username {
        font-size: 0.82rem;
        max-width: 120px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .so-body {
        font-size: 1rem;
        line-height: 1.35;
        margin-left: 0;
    }
    .so-action-row {
        margin-left: 0;
    }
    .so-reply-btn {
        font-size: 0.78rem;
    }

    /* ── Opinion Viewer mobile ── */
    .ov-card {
        border-radius: 10px;
        padding: 0.85rem;
        gap: 0.55rem;
    }
    .ov-avatar {
        width: 28px;
        height: 28px;
    }
    .ov-username {
        font-size: 0.78rem;
        max-width: 120px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .ov-body {
        font-size: 0.85rem;
        line-height: 1.6;
    }
    .ov-reply-avatar {
        width: 24px;
        height: 24px;
    }
    .ov-reply-input {
        font-size: 0.78rem;
    }
    .ov-btn-cancel,
    .ov-btn-submit {
        font-size: 0.72rem;
        padding: 0.3rem 0.8rem;
    }

    /* ── Reply Card mobile ── */
    .rc-thread {
        padding-left: calc(var(--depth, 0) * 0.5rem);
    }
    .rc-avatar-col {
        width: 24px;
    }
    .rc-avatar-col .so-avatar-outer {
        width: 24px;
        height: 24px;
    }
    .rc-avatar-col .so-avatar-outer .so-avatar {
        width: 24px;
        height: 24px;
    }
    .rc-avatar {
        width: 18px;
        height: 18px;
    }
    .rc-username {
        font-size: 0.72rem;
        max-width: 100px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .rc-body {
        font-size: 0.8rem;
    }
    .rc-show-replies,
    .rc-reply-btn {
        font-size: 0.68rem;
    }
    .rc-load-more {
        font-size: 0.7rem;
        margin-left: calc(24px + 0.65rem);
    }

    /* ── Write Opinion FAB mobile ── */
    .write-opinion-fab {
        right: 1.25rem;
        bottom: 6.5rem;
        width: 54px;
        height: 54px;
    }
}
@media(max-width: 432px){
    .oe-card {
        width: 92%;
    }

    .write-opinion-fab {
        right: 1rem;
        bottom: 6rem;
        width: 50px;
        height: 50px;
    }
}

.opinions-loading-container{
    display: flex;
    width: 100%;
    height: 100%;
    justify-content: center;
    align-items: center;
}
.side-bar-opinions-parent-container{
    display: flex;
    justify-content: flex-start;
    flex-direction: column;
    align-items: center;
    width: 98%;
    height: 100%;
    gap: 0.8rem;
}
.signal-container{
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-start;
    height: fit-content;
    width: 90%;
    margin-top: 1rem;
    padding: 0.8rem;
    border: 0.7px solid  rgba(151, 151, 151, 0.168);
    gap: 0.8rem;
    background-color: #D4A853;
    border-radius: 15px;
}
.signal-header{
    font-weight: 780;
    font-size: 1.1rem;
    line-height: 1.4rem;
    padding: 0;
    margin: 0;
}
.write-opinions-bttn {
  cursor: pointer;
  border: none;
  padding: 0.5rem 0.8rem;
  color: rgb(255, 255, 255);
  font-weight: 650;
  border-radius: 15px;
  background-color: rgb(4, 20, 29);
  transition: ease-in-out 0.2s;
}
.write-opinions-bttn:hover{
    background-color: #B8862D;
}

.latest-opinions-container{
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    justify-content: flex-start;
    width: 90%;
    padding: 0.8rem;
    border: 0.7px solid  rgba(151, 151, 151, 0.168);
    gap: 0.8rem;
    height: 480px;
    overflow-x: hidden;
    overflow-y: auto;
}
.latest-opinions-container::-webkit-scrollbar{
