/* ── Avatar Badge Rings ── */
.so-avatar-container,
.so-avatar-outer,
.ov-avatar-container,
.rc-avatar-container,
.opinions-profile-container {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
}
.avatar-ring-legend {
    border: 2px solid #FFD700;
    box-shadow:
        0 0 6px 1px rgba(255, 215, 0, 0.5),
        0 0 12px 2px rgba(255, 215, 0, 0.35),
        0 0 20px 4px rgba(255, 215, 0, 0.2);
    animation: glow-legend 2s ease-in-out infinite alternate;
}
.avatar-ring-og {
    border: 2px solid #9B59FF;
    box-shadow:
        0 0 6px 1px rgba(155, 89, 255, 0.5),
        0 0 12px 2px rgba(155, 89, 255, 0.35),
        0 0 20px 4px rgba(155, 89, 255, 0.2);
    animation: glow-og 2s ease-in-out infinite alternate;
}

@keyframes glow-legend {
    from {
        box-shadow:
            0 0 6px 1px rgba(255, 215, 0, 0.5),
            0 0 12px 2px rgba(255, 215, 0, 0.35),
            0 0 20px 4px rgba(255, 215, 0, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(255, 215, 0, 0.6),
            0 0 16px 4px rgba(255, 215, 0, 0.4),
            0 0 24px 6px rgba(255, 215, 0, 0.25);
    }
}

@keyframes glow-og {
    from {
        box-shadow:
            0 0 6px 1px rgba(155, 89, 255, 0.5),
            0 0 12px 2px rgba(155, 89, 255, 0.35),
            0 0 20px 4px rgba(155, 89, 255, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(155, 89, 255, 0.6),
            0 0 16px 4px rgba(155, 89, 255, 0.4),
            0 0 24px 6px rgba(155, 89, 255, 0.25);
    }
}
.so-avatar-outer.avatar-ring-legend,
.so-avatar-outer.avatar-ring-og {
    display: flex;
    align-items: center;
    justify-content: center;
    width: auto;
    height: auto;
}
.so-avatar-outer.avatar-ring-legend .so-avatar,
.so-avatar-outer.avatar-ring-og .so-avatar {
    width: 36px;
    height: 36px;
}

/* ── Sidebar Opinion Card (so-) — Borderless Timeline ── */
.so-card-wrapper {
    display: block;
    width: 100%;
    box-sizing: border-box;
    border-bottom: 1px solid var(--border-card);
    padding: 0;
    margin-bottom: 0;
    transition: background-color 0.15s ease;
}
.so-card-wrapper:hover {
    background-color: rgba(128, 128, 128, 0.03);
}
.so-avatar-outer {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    width: 34px;
    height: 34px;
    border-radius: 50%;
    background-color: transparent;
    cursor: pointer;
}
.so-avatar-outer .so-avatar {
    width: 34px;
    height: 34px;
    border-radius: 50%;
    object-fit: cover;
    border: 1px solid var(--border-card);
}
/* Small avatar variant for replies */
.so-avatar-outer--sm {
    width: 28px;
    height: 28px;
}
.so-avatar-outer--sm .so-avatar,
.so-avatar--sm {
    width: 28px;
    height: 28px;
}

.so-card {
    display: flex;
    flex-direction: column;
    width: 100%;
    box-sizing: border-box;
    background-color: transparent;
    border: none;
    border-radius: 0;
    padding: 1rem 0.75rem;
    color: var(--text-primary);
    box-shadow: none;
    transition: none;
}
.so-card:hover {
    box-shadow: none;
}

/* Parent card variant for detail view */
.so-card--parent {
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 16px;
    padding: 1.25rem;
    box-shadow: var(--shadow-card-sm);
}
.so-card--parent:hover {
    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
}

.visited-profile-opinions-container .so-card {
    border: none;
    box-shadow: none;
}

.so-card-content{
    display: flex;
    flex-direction: column;
    gap: 0.45rem;
    min-width: 0;
}
.so-card--profile{
    background-color: var(--bg-card);
}
.so-card--profile::before{
    content: none;
}
.so-card--profile .so-username,
.so-card--profile .so-body,
.so-card--profile .ov-date{
    color: inherit;
}

/* ── New header row (flat inline) ── */
.so-header-row {
    display: flex;
    align-items: center;
    gap: 0.45rem;
}
.so-dot {
    color: var(--text-faint);
    font-size: 0.75rem;
    line-height: 1;
    flex-shrink: 0;
}
.so-date {
    font-family: var(--font-ui);
    font-size: 0.75rem;
    color: var(--text-faint);
    white-space: nowrap;
    flex-shrink: 0;
}

.so-avatar {
    width: 34px;
    height: 34px;
    border-radius: 50%;
    object-fit: cover;
    cursor: pointer;
}
.so-username {
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 600;
    color: var(--text-heading);
    cursor: pointer;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}
.so-username:hover {
    color: var(--accent-amber);
}

.so-body {
    font-family: var(--font-serif);
    font-size: clamp(1.02rem, 0.96rem + 0.25vw, 1.2rem);
    line-height: 1.45;
    color: var(--text-primary);
    cursor: pointer;
    margin-left: 0;
    overflow-wrap: anywhere;
    word-break: break-word;
    white-space: pre-wrap;
    display: block;
    padding-top: 0.25rem;
}
/* Larger body for parent card in detail view */
.so-body--parent {
    font-size: clamp(1.08rem, 1rem + 0.3vw, 1.3rem);
    line-height: 1.55;
}

/* ── Action row ── */
.so-action-row {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    margin-left: 0;
    padding-top: 0.25rem;
}
.so-reply-btn {
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
    background-color: transparent;
    border: none;
    border-radius: 20px;
    padding: 0.3rem 0.75rem;
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-weight: 500;
    color: var(--text-muted);
    cursor: pointer;
    transition: color 0.15s ease, background-color 0.15s ease;
}
.so-reply-btn:hover {
    color: var(--accent-amber);
    background-color: rgba(212, 168, 83, 0.08);
}

.opinions-page-parent-container .so-card-wrapper {
    width: min(720px, 92%);
    margin: 0 auto;
}

/* ── Opinion Viewer (ov-) — kept for MyOpinions.jsx ── */
.ov-card {
    display: flex;
    flex-direction: column;
    width: 100%;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 14px;
    padding: 1.15rem;
    gap: 0.75rem;
    box-sizing: border-box;
    transition: box-shadow 0.25s ease;
    margin-bottom: 1rem;
}
.ov-card:hover {
    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
}

.ov-user-row {
    display: flex;
    align-items: center;
    gap: 0.45rem;
}
.ov-avatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
}
.ov-username {
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--text-heading);
    cursor: pointer;
    transition: color 0.15s ease;
}
.ov-username:hover {
    color: var(--accent-amber);
    text-decoration: underline;
}
.ov-dot {
    color: var(--text-separator);
    font-size: 0.8rem;
    line-height: 1;
}
.ov-date {
    font-family: var(--font-ui);
    font-size: 0.75rem;
    color: var(--text-faint);
}

.ov-body {
    font-family: var(--font-serif);
    font-size: 0.92rem;
    line-height: 1.7;
    color: var(--text-body);
    cursor: pointer;
}

.ov-meta-bar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: 0.6rem;
    border-top: 1px solid var(--border-card);
}
.ov-reply-pill {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    background-color: var(--bg-pill);
    border-radius: 10px;
    padding: 0.2rem 0.6rem;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-amber);
    cursor: pointer;
}
.ov-full-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

/* ── Opinion Viewer stats + divider ── */
.ov-stats-row {
    display: flex;
    align-items: center;
    gap: 0.45rem;
    padding-top: 0.35rem;
}
.ov-stats-row .ov-reply-count {
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--text-heading);
}
.ov-stats-row .so-dot {
    color: var(--text-faint);
    font-size: 0.75rem;
}
.ov-stats-row .ov-full-date {
    font-size: 0.75rem;
}
.ov-divider {
    width: 100%;
    height: 1px;
    background-color: var(--border-card);
    margin: 0.35rem 0;
}

/* ── Reply composer (ov-composer) ── */
.ov-composer {
    display: flex;
    align-items: flex-start;
    gap: 0.55rem;
    padding-top: 0.35rem;
}
.ov-composer-input-wrap {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
}
.ov-reply-row {
    display: flex;
    align-items: flex-end;
    gap: 0.5rem;
    padding-top: 0.25rem;
}
.ov-reply-avatar {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
}
.ov-reply-input {
    flex: 1;
    min-height: 1.4rem;
    outline: none;
    border: none;
    border-bottom: 1px solid var(--border-card);
    background-color: transparent;
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-style: normal;
    color: var(--text-primary);
    padding-bottom: 0.25rem;
    resize: none;
    transition: border-color 0.2s ease;
}
.ov-reply-input::placeholder {
    color: var(--text-faint);
}
