        padding: 0.85rem;
        gap: 0.55rem;
    }
    .ov-avatar {
        width: 28px;
        height: 28px;
    }
    .ov-username {
        font-size: 0.78rem;
        max-width: 120px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .ov-body {
        font-size: 0.85rem;
        line-height: 1.6;
    }
    .ov-reply-avatar {
        width: 24px;
        height: 24px;
    }
    .ov-reply-input {
        font-size: 0.78rem;
    }
    .ov-btn-cancel,
    .ov-btn-submit {
        font-size: 0.72rem;
        padding: 0.3rem 0.8rem;
