    }
    .rc-avatar-col .so-avatar-outer .so-avatar {
        width: 24px;
        height: 24px;
    }
    .rc-avatar {
        width: 18px;
        height: 18px;
    }
    .rc-username {
        font-size: 0.72rem;
        max-width: 100px;
