.opinions-loading-container{
    display: flex;
    width: 100%;
    height: 100%;
    justify-content: center;
    align-items: center;
}
.side-bar-opinions-parent-container{
    display: flex;
    justify-content: flex-start;
    flex-direction: column;
    align-items: center;
    width: 98%;
    height: 100%;
    gap: 0.8rem;
}
.signal-container{
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-start;
    height: fit-content;
    width: 90%;
    margin-top: 1rem;
    padding: 0.8rem;
    border: 0.7px solid  rgba(151, 151, 151, 0.168);
    gap: 0.8rem;
    background-color: #D4A853;
    border-radius: 15px;
