    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-amber);
    cursor: pointer;
}
.ov-full-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

/* ── Opinion Viewer stats + divider ── */
.ov-stats-row {
    display: flex;
    align-items: center;
    gap: 0.45rem;
    padding-top: 0.35rem;
}
.ov-stats-row .ov-reply-count {
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--text-heading);
}
.ov-stats-row .so-dot {
    color: var(--text-faint);
    font-size: 0.75rem;
}
.ov-stats-row .ov-full-date {
    font-size: 0.75rem;
}
.ov-divider {
    width: 100%;
    height: 1px;
    background-color: var(--border-card);
    margin: 0.35rem 0;
}

/* ── Reply composer (ov-composer) ── */
.ov-composer {
    display: flex;
    align-items: flex-start;
    gap: 0.55rem;
    padding-top: 0.35rem;
}
.ov-composer-input-wrap {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
}
.ov-reply-row {
    display: flex;
    align-items: flex-end;
    gap: 0.5rem;
    padding-top: 0.25rem;
}
.ov-reply-avatar {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
}
.ov-reply-input {
    flex: 1;
    min-height: 1.4rem;
    outline: none;
    border: none;
    border-bottom: 1px solid var(--border-card);
    background-color: transparent;
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-style: normal;
    color: var(--text-primary);
    padding-bottom: 0.25rem;
    resize: none;
    transition: border-color 0.2s ease;
}
.ov-reply-input::placeholder {
    color: var(--text-faint);
}
.ov-reply-input:focus {
    border-bottom: 2px solid var(--accent-amber);
}

.ov-composer-actions {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.6rem;
    overflow: hidden;
}
.ov-char-count {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 500;
    color: var(--text-faint);
}

.ov-btn-row {
    display: flex;
    gap: 0.6rem;
    justify-content: flex-end;
    overflow: hidden;
}
.ov-btn-cancel {
    cursor: pointer;
    background-color: transparent;
    border: 1px solid var(--border-card);
    color: var(--text-primary);
    border-radius: 20px;
    padding: 0.35rem 1rem;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 500;
    transition: background-color 0.15s ease;
}
.ov-btn-cancel:hover {
    background-color: var(--bg-hover);
}
.ov-btn-submit {
    cursor: pointer;
    border: none;
    padding: 0.35rem 1rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    transition: opacity 0.15s ease;
}
.ov-btn-submit:hover {
    opacity: 0.88;
}
.ov-btn-submit.ov-btn-disabled {
    cursor: default;
    user-select: none;
    opacity: 0.45;
}

/* ── Reply Card (rc-) — Avatar-column thread ── */
.rc-thread {
    padding-left: calc(var(--depth, 0) * 1rem);
    width: 100%;
    box-sizing: border-box;
}

.rc-reply {
    display: flex;
    gap: 0.65rem;
    padding: 0.65rem 0;
}

.rc-avatar-col {
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 32px;
    flex-shrink: 0;
}
.rc-connector {
    flex: 1;
    width: 2px;
    background-color: var(--border-card);
    border-radius: 1px;
    margin-top: 0.35rem;
    transition: background-color 0.2s ease;
}
.rc-reply:hover .rc-connector {
    background-color: var(--accent-amber);
}
.rc-connector--hidden {
    visibility: hidden;
}

.rc-content {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    flex: 1;
    min-width: 0;
}

.rc-user-row {
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.rc-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
}
.rc-username {
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-heading);
}
.rc-dot {
    color: var(--text-separator);
    font-size: 0.75rem;
    line-height: 1;
}
.rc-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

.rc-body {
    font-family: var(--font-serif);
    font-size: 0.85rem;
    line-height: 1.65;
    color: var(--text-body);
    overflow-wrap: anywhere;
    word-break: break-word;
    white-space: pre-wrap;
}

.rc-actions {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding-top: 0.15rem;
}
.rc-show-replies {
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--accent-amber);
    transition: opacity 0.15s ease;
}
.rc-show-replies:hover {
    opacity: 0.8;
}
.rc-reply-btn {
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--text-muted);
    transition: color 0.15s ease;
}
.rc-reply-btn:hover {
    color: var(--accent-amber);
}

.rc-inline-composer {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    overflow: hidden;
    padding-top: 0.25rem;
}

.rc-load-more {
    display: inline-flex;
    align-items: center;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.35rem 0;
    margin-top: 0.25rem;
    margin-left: calc(32px + 0.65rem);
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--accent-amber);
    transition: opacity 0.15s ease;
}
.rc-load-more:hover {
    opacity: 0.8;
}

