# Fix Mobile Spacing — Opinions Cards Too Flush to Screen Edges

## Context
After the borderless timeline redesign, `.so-card` lost its horizontal padding (`padding: 1rem 0`), and on mobile the cards sit flush against the screen edges. The content needs breathing room (horizontal padding) so it doesn't feel cramped on small screens.

## Root Cause
- `.so-card` has `padding: 1rem 0` (desktop) / `padding: 0.75rem 0` (mobile) — **zero horizontal padding**
- `.opinions-page-parent-container .so-card-wrapper` is `width: 94%` on mobile but the card itself has no internal padding
- `.so-card--parent` (opinion viewer) has `padding: 1.25rem` which is fine, but needs a mobile reduction
- `.visited-profile-opinions-container` has `padding: 1rem` which is fine but the cards inside have no padding

## Fix — CSS only (`sidebarOpinions.css`)

### 1. Add horizontal padding to `.so-card` (desktop + mobile)
```css
/* Desktop: add small horizontal padding */
.so-card {
    padding: 1rem 0.75rem;  /* was: 1rem 0 */
}

/* Mobile override */
@media(max-width: 480px) {
    .so-card {
        padding: 0.75rem 0.6rem;  /* was: 0.75rem 0 */
    }
}
```

### 2. Ensure `.so-card--parent` scales down on mobile
```css
@media(max-width: 480px) {
    .so-card--parent {
        padding: 0.85rem;
        border-radius: 12px;
    }
}
```

### 3. Ensure opinion viewer wrapper has horizontal padding on mobile
The opinion viewer renders inside the same `.opinions-page-parent-container` or route wrapper. The `.so-card-wrapper` width of 94% on mobile is fine but could use a small bump:
```css
@media(max-width: 480px) {
    .opinions-page-parent-container .so-card-wrapper {
        width: 92%;  /* was 94%, gives more edge breathing room */
    }
}
```

### 4. Reply threads — add horizontal padding
The `.rc-reply` content also needs small padding within the `.rc-content` block, and the `.rc-inline-composer` textarea should not touch the edges.
```css
@media(max-width: 480px) {
    .rc-reply {
        gap: 0.45rem;  /* was 0.65rem, save space on small screens */
    }
}
```

### 5. Visited profile opinions container — tighten on mobile
```css
@media(max-width: 480px) {
    .visited-profile-opinions-container {
        width: 95%;
        padding: 0.65rem;
    }
}
```

## File to Modify
- `client/src/components/SidebarOpinions/sidebarOpinions.css` — CSS-only changes in desktop defaults + `@media(max-width: 480px)` block

## Verification
1. OpinionsPage on mobile (< 480px): cards have visible horizontal padding, text doesn't touch screen edges
2. OpinionViewer on mobile: parent card has padding, reply composer has breathing room
3. Reply threads on mobile: content doesn't touch edges, nested threads still indent properly
4. Visited profile opinions on mobile: glass container and cards have spacing
5. Desktop: minimal visual change (slight horizontal padding added, looks intentional)
6. Sidebar context: unchanged (sidebar already has container padding from `.latest-opinions-container`)

import { useEffect, useRef } from 'react';
import './mobilesidebarlink.css';
import { AnimatePresence, motion } from 'framer-motion';
import { useAuth } from '../../Context/useAuth';
import { useTheme } from '../../Context/useTheme';
import { useLocation, useNavigate } from 'react-router-dom';
import { preloadProfileRoute } from '../../utils/preloadRoutes';

const MobileSidebarLink = ({onclose}) => {
    const {user, signOut, notifCount} = useAuth();
    const {theme, toggleTheme} = useTheme();
    const navigate = useNavigate();
    const location = useLocation();
    const userData = user?.userData?.[0];

    const clickProfile = () =>{
        preloadProfileRoute();
        navigate('/profile')
    }

    useEffect(() => {
        preloadProfileRoute();
    }, []);

    const handleClose =(e) =>{
        e.stopPropagation();
        onclose();
    }
    const navigatePath = (path) =>{
        navigate(path);
        return onclose()
    }

    return(
        <>
        <AnimatePresence>
        <div onClick={(e) => handleClose(e)} className="mobile-sidebar-bg">
            <motion.div
            initial={{x: -30}}
            animate={{opacity: 1, x: 0, transition: {duration: 0.18, ease: 'easeOut'}}}
            exit={{x: -30, transition: {duration: 0.14, ease: 'easeIn'}}}
            onClick={(e) => e.stopPropagation()} className='mobile-sidebar-link-container'
            >
                <div className='sidebar-profile-container'>

                    <div onClick={(e) => clickProfile()} className='sidebar-profile-avatar-container'>
                        <img className='sidebar-profile-avatar' src={userData?.image_url || '/assets/profile.jpg'} alt={`${userData?.name || "User"} profile picture`} />
                    </div>

                    <div onClick={userData ? signOut : () => navigatePath('/login')} className='sidebar-signout-bttn'>
                        {userData ? 'Sign Out' : 'Log In'}
                    </div>

                </div>
                <div onClick={(e) => clickProfile()} className='sidebar-profile-metadata'>
                    <p>{userData?.name}</p>
                    <p style={{fontWeight: 500, fontSize: '0.8rem'}}>{userData?.user_email}</p>
                </div>

                <div onClick={() => navigatePath('/home/notifications')} className='sidebar-nav-container'>
                    <div className={location.pathname === '/home/notifications' ? 'sidebar-nav-bttn-active' : 'sidebar-nav-bttn'}>
                        <div className="sidebar-notif-label">
                            Notifications
                            {notifCount > 0 && (
                                <span className="sidebar-notif-badge">{notifCount}</span>
                            )}
                        </div>
                        <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={location.pathname === '/home/notifications' ? "#D4A853" : "#b6b6b6"}>
                            <path fillRule="evenodd" clipRule="evenodd" d="M14.802 19.8317C15.4184 19.7699 15.8349 20.4242 15.5437 20.9539C15.3385 21.3271 15.0493 21.6529 14.7029 21.9197C14.3496 22.1918 13.9397 22.4006 13.5 22.5408C13.0601 22.6812 12.593 22.7522 12.1242 22.7522C11.6554 22.7522 11.1883 22.6812 10.7484 22.5408C10.3087 22.4006 9.89883 22.1918 9.54556 21.9197C9.1991 21.6529 8.90988 21.3271 8.70472 20.9539C8.41354 20.4242 8.83002 19.7699 9.44644 19.8317C9.63869 19.851 11.1433 19.9981 12.1242 19.9981C13.1051 19.9981 14.6097 19.851 14.802 19.8317Z" />
                            <path fillRule="evenodd" clipRule="evenodd" d="M8.52901 2.08755C10.7932 1.00445 13.4465 0.967602 15.7423 1.98737L15.9475 2.07851C18.3532 3.14707 19.8934 5.4622 19.8934 8.0096L19.8934 9.27297C19.8934 10.2885 20.1236 11.2918 20.5681 12.213L20.8335 12.7632C22.0525 15.29 20.465 18.2435 17.6156 18.7498L17.455 18.7783C13.93 19.4046 10.3154 19.4046 6.79044 18.7783C3.90274 18.2653 2.37502 15.1943 3.77239 12.7115L3.99943 12.3082C4.55987 11.3124 4.85335 10.1981 4.85335 9.06596L4.85335 7.79233C4.85335 5.3744 6.27704 3.16478 8.52901 2.08755Z" />
                        </svg>
                    </div>
                </div>

                <div onClick={() => navigatePath('/home/bookmark')} className='sidebar-nav-container'>
                    <div className={location.pathname === '/home/bookmark' ? 'sidebar-nav-bttn-active' : 'sidebar-nav-bttn'}>
                        Bookmarks
                        <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="none">
