 84→                        <polyline points="14 2 14 8 20 8"/>
 85→                        <line x1="16" y1="13" x2="8" y2="13"/>
 86→                        <line x1="16" y1="17" x2="8" y2="17"/>
 87→                        <polyline points="10 9 9 9 8 9"/>
 88→                    </svg>
 89→                    <p>No drafts yet</p>
 90→                    <span>Start writing and your work will be saved automatically</span>
 91→                </div>
 92→            ) : (
 93→                <div className="draft-list-items">
 94→                    {drafts.map((draft) => (
 95→                        <div
 96→                            key={draft.id}
 97→                            className="draft-list-item"
 98→                            onClick={() => handleResumeDraft(draft)}
 99→                        >
100→                            <div className="draft-list-item-content">
101→                                <span className="draft-list-item-title">
102→                                    {draft.title?.trim() || 'Untitled'}
103→                                </span>
104→                                <span className="draft-list-item-date">
105→                                    Edited {formatDate(draft.updated_at || draft.created_at)}
106→                                </span>
107→                            </div>
108→                            <button
109→                                className="draft-list-item-delete"
110→                                onClick={(e) => handleDeleteDraft(e, draft.id)}
111→                                aria-label="Delete draft"
112→                                title="Delete draft"
113→                            >
114→                                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
115→                                    <polyline points="3 6 5 6 21 6"/>
116→                                    <path d="M19 6l-2 14H7L5 6"/>
117→                                    <path d="M10 11v6"/>
118→                                    <path d="M14 11v6"/>
119→                                    <path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/>
120→                                </svg>
121→                            </button>
122→                        </div>
123→                    ))}
124→                </div>
125→            )}
126→        </div>
127→    );
128→};
129→
130→export default DraftList;
