 31→export const saveJournalImage = (token, body) =>
 32→    authedFormRequest(token, 'POST', '/save-journal-image', body, 'error uploading journal images');
 33→
 34→export const saveJournal = (token, body) =>
 35→    authedFormRequest(token, 'POST', '/save-journal', body, 'failed to save journal');
 36→
