 40→export const deleteJournalImage = async (token, url) => {
 41→    const data = { filepath: [] };
 42→    if (url.length) {
 43→        url.forEach(element => {
 44→            data.filepath.push(element.split('/journal-images/').pop());
 45→        });
 46→    }
 47→    return authedJsonRequest(token, 'POST', '/delete-journal-images', data, 'failed to delete journal images');
 48→};
