 81→export const searchUsers = (query, limit = 10) => {
 82→    const q = typeof query === 'string' ? query.trim() : '';
 83→    if (!q) return Promise.resolve({ data: [], hasMore: false });
 84→    return publicGet(`/users/search?query=${encodeURIComponent(q)}&limit=${limit}`, 'failed to search users');
 85→};
