 87→export const searchFollowingUsers = (token, query = '', limit = 10) => {
 88→    const params = new URLSearchParams({ limit: String(limit) });
 89→    if (query) params.set('query', query);
 90→    return authedGet(token, `/users/following/search?${params}`, 'failed to search following users');
 91→};
