101→export const getJournalById = (journalId, userId, options = {}) => {
102→    if (!journalId) throw new Error('journalId is required');
103→    const params = new URLSearchParams();
104→    if (userId) params.set('userId', String(userId));
105→    if (options.includeRepostContent) params.set('includeRepostContent', 'true');
106→    const qs = params.toString();
107→    const path = qs
108→        ? `/journal/${encodeURIComponent(journalId)}?${qs}`
109→        : `/journal/${encodeURIComponent(journalId)}`;
110→    return publicGet(path, 'failed to fetch journal');
111→};
